+export async function transferirStockCombo(comboId: string, cantidad: number, tallaCombo: string) {
+  try {
+    const combo = await prisma.prenda.findUnique({ where: { id: comboId } });
+    if (!combo) throw new Error("Conjunto no encontrado");
+
+    if (combo.piezasId.length === 0) throw new Error("El conjunto no tiene prendas vinculadas");
+
+    const prendas = await prisma.prenda.findMany({
+      where: { id: { in: combo.piezasId } }
+    });
+
+    // Validar si todas las prendas tienen suficiente stock
+    for (const prenda of prendas) {
+      if (prenda.stockPorTalla && Object.keys(prenda.stockPorTalla).length > 0) {
+        const stockTalla = Number((prenda.stockPorTalla as Record<string, string>)[tallaCombo] || 0);
+        if (stockTalla < cantidad) {
+          throw new Error(`La prenda ${prenda.nombre} no tiene suficiente stock en la talla ${tallaCombo}.`);
+        }
+      } else {
+        if (prenda.stockCount < cantidad) {
+          throw new Error(`La prenda ${prenda.nombre} no tiene suficiente stock (requiere ${cantidad}, tiene ${prenda.stockCount}).`);
+        }
+      }
+    }
+
+    // Efectuar el descuento en las prendas individuales
+    await prisma.$transaction(async (tx) => {
+      for (const prenda of prendas) {
+        if (prenda.stockPorTalla && Object.keys(prenda.stockPorTalla).length > 0) {
+          const nuevoStockTalla = { ...(prenda.stockPorTalla as Record<string, string>) };
+          nuevoStockTalla[tallaCombo] = (Number(nuevoStockTalla[tallaCombo]) - cantidad).toString();
+          
+          await tx.prenda.update({
+            where: { id: prenda.id },
+            data: { stockPorTalla: nuevoStockTalla }
+          });
+        } else {
+          await tx.prenda.update({
+            where: { id: prenda.id },
+            data: { stockCount: prenda.stockCount - cantidad }
+          });
+        }
+      }
+
+      // Sumar al combo
+      const nuevoStockCombo = { ...((combo.stockPorTalla || {}) as Record<string, string>) };
+      nuevoStockCombo[tallaCombo] = (Number(nuevoStockCombo[tallaCombo] || 0) + cantidad).toString();
+      
+      const newTallas = [...combo.tallas];
+      if (!newTallas.includes(tallaCombo)) newTallas.push(tallaCombo);
+
+      await tx.prenda.update({
+        where: { id: combo.id },
+        data: { 
+          stockPorTalla: nuevoStockCombo,
+          tallas: newTallas
+        }
+      });
+    });
+
+    revalidatePath("/admin/productos");
+    return { success: true };
+  } catch (error: any) {
+    return { success: false, error: error.message };
+  }
